Here's how to structure your tests using modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static DataFetcher CreateFetcher(HttpStatusCode status, string content)
    {
        var handler = new FakeHandler(new HttpResponseMessage(status)
        {
            Content = new StringContent(content)
        });
        return new DataFetcher(new HttpClient(handler));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var fetcher = CreateFetcher(HttpStatusCode.OK, "hello");

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var fetcher = CreateFetcher(HttpStatusCode.NotFound, "");

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — a handler that delays so cancellation fires first
        using var cts = new CancellationTokenSource();
        var handler = new DelayedHandler(TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act — cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handlers — no mocking library needed
    private sealed class FakeHandler(HttpResponseMessage response) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }

    private sealed class DelayedHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns used:**

- **`TestContext.CancellationToken`** — passed to `FetchAsync` in timeout-guarded tests so `[Timeout(5000)]` can actually cancel the call cooperatively
- **`Assert.ThrowsExactlyAsync`** — replaces `[ExpectedException]`; lets you inspect the exception and keeps the test precise
- **Cancellation test** — creates a pre-cancelled `CancellationTokenSource` paired with a `DelayedHandler`, proving your code respects the token
- **Custom `HttpMessageHandler`** — avoids mocking `HttpClient` directly (which doesn't work well); intercepts at `SendAsync` instead
- **Sealed class + constructor-injected `TestContext`** — modern MSTest 3.x+ conventions
